```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // packet_id
        stream & packet_id;

        // username with length prefix
        stream & hexi::prefixed(username);

        // scores: write count first, then elements using operator<<
        std::uint32_t count = static_cast<std::uint32_t>(scores.size());
        stream & count;
        stream << scores; // uses write_container internally

        // metadata as null-terminated string
        stream & hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use the stream's serialise method to invoke NetworkPacket::serialise
    stream.serialise(const_cast<NetworkPacket&>(packet));

    return buffer;
}
```

