#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create a read-only adaptor and stream over the incoming buffer
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket pkt{};

    // 1. Read packet_id (first 4 bytes)
    stream(pkt.packet_id);

    // 2. Read username with a length prefix
    //    Assuming uint32_t length prefix; Hexi's prefixed adaptor handles this.
    {
        std::string tmp_username;
        stream(hexi::prefixed<std::uint32_t>(tmp_username));
        pkt.username = std::move(tmp_username);
    }

    // 3. Read score count, then read container with that count
    std::uint32_t score_count = 0;
    stream(score_count);
    pkt.scores.resize(score_count);
    stream.read_container(pkt.scores);

    // 4. Read metadata as a null-terminated string for zero-copy,
    //    then copy into std::string.
    {
        std::string_view metadata_view;
        stream(hexi::null_terminated(metadata_view));
        pkt.metadata.assign(metadata_view.begin(), metadata_view.end());
    }

    // 5. Skip any remaining padding bytes (if any)
    auto remaining = adaptor.size() - adaptor.read_position();
    if (remaining > 0) {
        stream.skip(remaining);
    }

    return pkt;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    PacketInfo info{};

    // 1. Use span() to get a zero-copy view of packet_id (first 4 bytes)
    {
        std::span<const std::uint8_t> id_span;
        stream(hexi::span(id_span, sizeof(std::uint32_t)));

        // Reinterpret the bytes as uint32_t.
        // Hexi's serialization is contiguous; assume correct alignment here.
        info.packet_id = *reinterpret_cast<const std::uint32_t*>(id_span.data());
    }

    // 2. Read username using prefixed adaptor as a string_view (zero-copy)
    stream(hexi::prefixed<std::uint32_t>(info.username));

    // 3. Skip the scores vector without reading its elements:
    //    read the count, then skip count * sizeof(uint32_t) bytes.
    std::uint32_t score_count = 0;
    stream(score_count);
    if (score_count != 0) {
        stream.skip(score_count * sizeof(std::uint32_t));
    }

    // Note: metadata and any padding are left unread; this function is
    // intentionally partial.

    return info;
}
