#include <hexi/hexi.h>
#include <string>
#include <cstdint>
#include <span>

struct UserData {
    uint64_t user_id;
    uint8_t age;
    std::string name;

    void serialise(auto& stream) {
        stream(user_id, age, name);
    }
};

UserData deserialize_user_data(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    UserData user;
    stream.deserialise(user);

    return user;
}

test cases:
#include <gtest/gtest.h>
#include <hexi/hexi.h>
#include <string>
#include <cstdint>
#include <span>
#include <vector>

// Include the implementation
#include "implementation.hpp"

// Helper function to create test buffer
std::vector<uint8_t> create_user_buffer(uint64_t user_id, uint8_t age, const std::string& name) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << user_id << age << name;
    return buffer;
}

TEST(UserData, Deserialize) {
    auto buffer = create_user_buffer(123456789, 25, "Alice");

    UserData user = deserialize_user_data(buffer);

    EXPECT_EQ(123456789, user.user_id);
    EXPECT_EQ(25, user.age);
    EXPECT_EQ("Alice", user.name);
}

TEST(UserData, DeserializeLongName) {
    auto buffer = create_user_buffer(987654321, 30, "VeryLongUserNameThatShouldWork");

    UserData user = deserialize_user_data(buffer);

    EXPECT_EQ(987654321, user.user_id);
    EXPECT_EQ(30, user.age);
    EXPECT_EQ("VeryLongUserNameThatShouldWork", user.name);
}

TEST(UserData, DeserializeEmptyName) {
    auto buffer = create_user_buffer(111, 18, "");

    UserData user = deserialize_user_data(buffer);

    EXPECT_EQ(111, user.user_id);
    EXPECT_EQ(18, user.age);
    EXPECT_TRUE(user.name.empty());
}

