```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t  version;
    uint8_t  flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a read-only adaptor over the input span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream  stream(adaptor);

    // Get a zero-copy span over the header bytes
    // The library's span<T>() gives a view into the underlying buffer
    auto header_span = stream.span<std::byte>(sizeof(PacketHeader));

    // Interpret the span as a PacketHeader without copying
    const auto* header_ptr =
        reinterpret_cast<const PacketHeader*>(header_span.data());

    return *header_ptr;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream  stream(adaptor);

    // Get a zero-copy view (pointer + length) to a null-terminated string.
    // view<char>() reads until the delimiter (default '\0') without copying.
    auto msg_view = stream.view<char>();

    return std::string_view{msg_view.data(), msg_view.size()};
}
```

