```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a read-only adaptor over the existing buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Determine how many bytes we can safely peek
    const std::size_t available = adaptor.size();
    const std::size_t to_copy = std::min<std::size_t>(bytes_to_peek, available);

    // Prepare destination vector
    std::vector<uint8_t> result(to_copy);

    // Copy without advancing the read cursor
    if (to_copy > 0) {
        adaptor.copy(result.data(), to_copy);
    }

    return result;
}
```

