```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Use a read-only adaptor over the given buffer.
    // For an empty buffer, data() is allowed to return nullptr.
    hexi::buffer_adaptor adaptor(buffer);
    // buffer_adaptor exposes the underlying contiguous storage via .data()
    auto* data = adaptor.data();
    return reinterpret_cast<const uint8_t*>(data);
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Use a mutable adaptor over the given buffer.
    hexi::buffer_adaptor adaptor(buffer);
    auto* data = adaptor.data();
    return reinterpret_cast<uint8_t*>(data);
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    BufferInfo info{};
    // How many bytes are currently readable according to Hexi
    info.readable_size = adaptor.size();
    // Free space is the remaining capacity in the underlying vector
    info.free_space = buffer.capacity() - buffer.size();
    return info;
}
