#include <gtest/gtest.h>
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

// Include the implementation
#include "implementation.hpp"

// Helper function to create test buffer for integers
std::vector<uint8_t> create_int_buffer(const std::vector<uint32_t>& items) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    uint8_t data_type = 0;
    uint32_t count = static_cast<uint32_t>(items.size());
    stream << data_type << count << items;

    return buffer;
}

// Helper function to create test buffer for floats
std::vector<uint8_t> create_float_buffer(const std::vector<float>& items) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    uint8_t data_type = 1;
    uint32_t count = static_cast<uint32_t>(items.size());
    stream << data_type << count << items;

    return buffer;
}

TEST(BufferPreview, PreviewAndReadInts) {
    std::vector<uint32_t> expected = {10, 20, 30, 40};
    auto buffer = create_int_buffer(expected);

    DataResult result = preview_and_read_data(buffer);

    EXPECT_EQ(0, result.data_type);
    EXPECT_EQ(expected, result.int_items);
    EXPECT_TRUE(result.float_items.empty());
}

TEST(BufferPreview, PreviewAndReadFloats) {
    std::vector<float> expected = {1.5f, 2.5f, 3.5f};
    auto buffer = create_float_buffer(expected);

    DataResult result = preview_and_read_data(buffer);

    EXPECT_EQ(1, result.data_type);
    EXPECT_EQ(expected, result.float_items);
    EXPECT_TRUE(result.int_items.empty());
}

