#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Adapt the read-only span into a Hexi buffer, then a binary_stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // 1. Preview the first byte (data_type) without advancing the read pointer
    //    We can use the buffer_adaptor's read interface directly for peeking.
    auto& read_buf = stream.read_buffer(); // obtain underlying read buffer
    if (read_buf.size() < 1) {
        // Not enough data even for data_type; stream will be in error state anyway.
        return result;
    }

    // Peek the first byte: data_type
    result.data_type = static_cast<uint8_t>(
        std::to_integer<unsigned char>(read_buf[0])
    );

    // 2. Check that we have enough data for at least the header:
    //    data_type (1 byte) + item_count (4 bytes)
    if (read_buf.size() < 1 + sizeof(uint32_t)) {
        return result;
    }

    // 3. Now actually read from the stream (this advances the read pointer)

    // Read data_type (we already peeked, but now we consume it)
    uint8_t data_type{};
    stream >> data_type;

    // Read item_count
    uint32_t item_count{};
    stream >> item_count;

    // 4. Check that the remaining bytes are enough for all items
    const std::size_t bytes_per_item =
        (data_type == 0) ? sizeof(uint32_t) : sizeof(float);

    // Remaining bytes in the buffer after reading header
    const std::size_t remaining_bytes = read_buf.size() - stream.tellg();

    if (remaining_bytes < bytes_per_item * static_cast<std::size_t>(item_count)) {
        // Not enough data to read all items; return what we have with header info
        return result;
    }

    // 5. Read the items based on data_type
    if (data_type == 0) {
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (data_type == 1) {
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    // Store the data_type we actually read (should match peeked)
    result.data_type = data_type;

    return result;
}
