```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create a mutable span over the buffer
    std::span<std::uint8_t> span(buffer.data(), buffer.size());

    // Create a buffer adaptor and a non-throwing binary_stream
    hexi::buffer_adaptor adaptor(span);
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Calculate required size: header (uint32_t) + container size metadata + data
    // Hexi stores containers as: size (uint64_t) + elements
    std::size_t required =
        sizeof(std::uint32_t) +                      // header
        sizeof(std::uint64_t) +                      // container size
        items.size() * sizeof(std::uint32_t);        // elements

    if (adaptor.write_remaining() < required) {
        return false; // insufficient space
    }

    // Write header and items
    stream << header;
    stream.write_container(items);

    // Success if stream did not enter an error state
    return static_cast<bool>(stream);
}
