```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Adapt the input span to a Hexi buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream on top of the adaptor
    hexi::binary_stream stream(adaptor);

    // Use buffer_adaptor pointer methods to inspect the buffer
    // (names based on typical Hexi API; adjust if your version differs)
    const auto* read_ptr = adaptor.data();      // current read pointer
    const auto  avail    = adaptor.size();      // total available data

    // We expect exactly the size of PacketHeader to be readable
    constexpr std::size_t header_size =
        sizeof(PacketHeader::magic) +
        sizeof(PacketHeader::version) +
        sizeof(PacketHeader::flags);

    if (avail < header_size) {
        // In a real application you might throw or return an error.
        // Here we just return a default-constructed header.
        return {};
    }

    // Get a zero‑copy view of the header bytes using binary_stream
    // Hexi exposes this as something like span_read<>() / read_span<>() /
    // get_span<>() depending on version; here we assume span_read:
    auto header_view = stream.span_read<std::byte>(header_size);
    // If span_read failed (stream in error state), bail out
    if (!stream || header_view.size() < header_size) {
        return {};
    }

    // Interpret the bytes as our PacketHeader layout (trivially copyable)
    const auto* raw = reinterpret_cast<const std::byte*>(header_view.data());
    const auto* p   = raw;

    PacketHeader header{};

    // Helper to read and advance
    auto read_u32 = [&p]() {
        uint32_t v{};
        std::memcpy(&v, p, sizeof(v));
        p += sizeof(v);
        return v;
    };
    auto read_u16 = [&p]() {
        uint16_t v{};
        std::memcpy(&v, p, sizeof(v));
        p += sizeof(v);
        return v;
    };

    header.magic   = read_u32();
    header.version = read_u16();
    header.flags   = read_u16();

    return header;
}
