```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Wrap the input span in a Hexi buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read the header
    uint32_t header{};
    stream >> header;

    // Find the null terminator for the message
    // We need a view into the underlying buffer, then search for '\0'
    auto view = stream.view<std::span<const char>>();

    // The view starts at the current read position;
    // search for the first '\0' byte.
    std::size_t idx = 0;
    for (; idx < view.size(); ++idx) {
        if (view[idx] == '\0') {
            break;
        }
    }

    // Construct a string_view over the bytes up to (but not including) the null
    std::string_view message(view.data(), idx);

    return MessagePacket{
        header,
        message
    };
}
