```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer,
                                           size_t bytes_to_peek)
{
    // dynamic_buffer in Hexi models the pmc::buffer_read interface, which
    // provides unchecked_read(offset, std::byte*, size). That function
    // reads from an absolute offset (0 = beginning), independent of and
    // without changing the current read cursor.
    //
    // The dynamic_buffer also exposes:
    //   - size()    : total bytes written
    //   - read_pos(): current read cursor
    //
    // We use these to copy from the current read cursor, without moving it.

    using std::byte;

    const auto available = buffer.size() - buffer.read_pos();
    if (bytes_to_peek > available) {
        bytes_to_peek = available;
    }

    std::vector<std::uint8_t> out(bytes_to_peek);

    if (bytes_to_peek == 0) {
        return out;
    }

    // unchecked_read expects std::byte*, so we reinterpret the uint8_t data.
    byte* dest = reinterpret_cast<byte*>(out.data());
    buffer.unchecked_read(buffer.read_pos(), dest, bytes_to_peek);

    return out;
}
```

