    hexi::tls_block_allocator<hexi::detail::intrusive_storage<block_size>, allocator_count>;

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
void enter_thread_with_allocator(tls_allocator_type<block_size, allocator_count>& allocator) {
	// Initialize/attach the allocator for the current thread.
	// According to the typical TLS allocator pattern in Hexi,
	// this is usually done via a thread_enter()/enter() style API.
	allocator.thread_enter();
}

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
void exit_thread_with_allocator(tls_allocator_type<block_size, allocator_count>& allocator) {
	// Clean up the allocator for the current thread.
	// Matching counterpart of enter_thread_with_allocator.
	allocator.thread_exit();
}
