#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <array>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<std::size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // The block_allocator manages a fixed number of blocks of a given type.
    // It keeps an internal free list; allocate() internally does a pop()
    // from that free list, and deallocate() internally does a push()
    // back onto that free list.
    //
    // To observe the behavior, we:
    // 1. Allocate several blocks and print their addresses.
    // 2. Deallocate them in a known order.
    // 3. Allocate again and see from the addresses that:
    //    - The most recently deallocated block is reused first
    //      (LIFO behavior of the internal free list).

    using value_type = std::uint64_t;
    hexi::block_allocator<value_type, element_count> alloc;

    // Step 1: allocate a subset of blocks
    constexpr std::size_t alloc_count = element_count / 2;
    std::array<value_type*, alloc_count> ptrs{};

    std::cout << "=== Initial allocations ===\n";
    for (std::size_t i = 0; i < alloc_count; ++i) {
        ptrs[i] = alloc.allocate();
        *ptrs[i] = static_cast<value_type>(i);
        std::cout << "Allocated ptrs[" << i << "] at " << static_cast<void*>(ptrs[i])
                  << " with value " << *ptrs[i] << '\n';
    }

    // Step 2: deallocate in forward order; internally this "pushes" onto the free list.
    std::cout << "\n=== Deallocation in forward order (0 -> "
              << (alloc_count - 1) << ") ===\n";
    for (std::size_t i = 0; i < alloc_count; ++i) {
        std::cout << "Deallocating ptrs[" << i << "] at " << static_cast<void*>(ptrs[i])
                  << '\n';
        alloc.deallocate(ptrs[i]);
    }

    // Step 3: re-allocate the same number of blocks and print their addresses.
    // Because the free list is LIFO, we expect to get the most recently freed
    // pointer first (i.e., ptrs[alloc_count - 1]), then ptrs[alloc_count - 2], etc.
    std::cout << "\n=== Re-allocations (showing LIFO free list behavior) ===\n";
    for (std::size_t i = 0; i < alloc_count; ++i) {
        value_type* p = alloc.allocate();
        *p = static_cast<value_type>(100 + i);
        std::cout << "Re-allocated block at " << static_cast<void*>(p)
                  << " with new value " << *p << '\n';
    }

    // Note: We deliberately do not fully exhaust all element_count blocks here;
    // the goal is just to show that the allocator reuses recently freed
    // blocks first, which reflects the internal push/pop behavior.
}
