template<hexi::endian::conversion conv, typename T>
T convert_with_enum(T value) {
    using hexi::endian;

    if constexpr (conv == endian::conversion::big_to_native) {
        return endian::big_to_native(value);
    } else if constexpr (conv == endian::conversion::native_to_big) {
        return endian::native_to_big(value);
    } else if constexpr (conv == endian::conversion::little_to_native) {
        return endian::little_to_native(value);
    } else if constexpr (conv == endian::conversion::native_to_little) {
        return endian::native_to_little(value);
    } else {
        static_assert(conv == endian::conversion::big_to_native ||
                      conv == endian::conversion::native_to_big ||
                      conv == endian::conversion::little_to_native ||
                      conv == endian::conversion::native_to_little,
                      "Unknown hexi::endian::conversion value");
        return value; // Unreachable, but required for some compilers
    }
}
