```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min
#include <cstddef>   // for std::byte

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    size_t bytes_to_preview
) {
    // Compute how many bytes are actually readable
    const size_t readable =
        (storage.write_offset >= storage.read_offset)
            ? static_cast<size_t>(storage.write_offset - storage.read_offset)
            : 0; // intrinsic_storage is linear, should not wrap

    const size_t to_copy = std::min(readable, bytes_to_preview);

    std::vector<uint8_t> out;
    out.reserve(to_copy);

    // storage.storage is an array of value_type (default std::byte)
    // Convert to uint8_t for the preview
    for(size_t i = 0; i < to_copy; ++i) {
        const auto& v = storage.storage[storage.read_offset + i];
        if constexpr (std::is_same_v<typename hexi::detail::intrusive_storage<block_size>::value_type, std::byte>) {
            out.push_back(static_cast<uint8_t>(v));
        } else {
            out.push_back(static_cast<uint8_t>(v));
        }
    }

    return out;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

inline BufferStatus<> check_buffer_status(
    const hexi::detail::intrusive_storage<1024>& storage
) {
    BufferStatus<> status{};

    // Readable size: data between read_offset and write_offset
    if (storage.write_offset >= storage.read_offset) {
        status.readable_size =
            static_cast<size_t>(storage.write_offset - storage.read_offset);
    } else {
        // For intrusive_storage as implemented, offsets should not wrap, but
        // guard anyway.
        status.readable_size = 0;
    }

    // Free space: remaining capacity in the current block
    constexpr size_t capacity = 1024;
    if (storage.write_offset <= capacity) {
        status.free_space =
            capacity - static_cast<size_t>(storage.write_offset);
    } else {
        status.free_space = 0;
    }

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use the provided clear() API which resets read and write offsets
    storage.clear();
}
