#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path,
                                    size_t bytes_to_read) {
    // Open file for reading
    hexi::file_buffer buffer(file_path);

    // Limit to available readable bytes
    const std::size_t available = buffer.size();
    const std::size_t to_read   = std::min<std::size_t>(bytes_to_read, available);

    std::vector<std::uint8_t> out(to_read);
    if (to_read > 0) {
        // Read advances the file_buffer's read pointer
        buffer.read(out.data(), to_read);
    }
    return out;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path,
                                       size_t bytes_to_preview) {
    // Open file for reading
    hexi::file_buffer buffer(file_path);

    const std::size_t available = buffer.size();
    const std::size_t to_copy   = std::min<std::size_t>(bytes_to_preview, available);

    std::vector<std::uint8_t> out(to_copy);
    if (to_copy > 0) {
        // copy() should not advance the internal read pointer
        buffer.copy(out.data(), to_copy);
    }
    return out;
}

void write_file_data(const std::filesystem::path& file_path,
                     const std::vector<uint8_t>& data) {
    // Open (or create) file for writing; depending on Hexi's API,
    // this constructor typically opens in read/write or write mode.
    hexi::file_buffer buffer(file_path, hexi::file_mode::write);

    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path);
    return buffer.size();
}
