#include <hexi/file_buffer.h>
#include <filesystem>

size_t get_file_readable_size(const std::filesystem::path& file_path) {
    // Open the file in read-only mode using Hexi's file_buffer
    hexi::file_buffer fb(file_path.string().c_str(), "rb");
    if (!fb) {
        // If the buffer is not valid, there is no readable data
        return 0;
    }

    // Hexi's file_buffer usually exposes size() as the amount of readable data
    return fb.size();
}

bool is_file_buffer_valid(const std::filesystem::path& file_path) {
    // Attempt to open the file using Hexi's file_buffer
    hexi::file_buffer fb(file_path.string().c_str(), "rb");

    // Hexi file_buffer is context-convertible to bool for error checking
    return static_cast<bool>(fb);
}
