output.text:
```cpp
#include <hexi/file_buffer.h>
#include <hexi.h>              // for hexi::binary_stream (depending on project layout)
#include <vector>
#include <cstdint>
#include <filesystem>
#include <algorithm>           // for std::min

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Open the file buffer for reading
    hexi::file_buffer file(file_path.string().c_str());

    // Use a binary_stream in no-throw mode so we can check state instead of exceptions
    hexi::binary_stream stream(file, hexi::no_throw);

    // Determine how many bytes we can actually read without error
    // (header_size might be larger than remaining data)
    std::vector<std::uint8_t> header(header_size);

    // Read up to header_size bytes
    const auto bytes_read = stream.read(
        header.data(),
        header.size()
    );

    // If read failed entirely, return empty
    if (bytes_read == 0 && !stream) {
        return {};
    }

    header.resize(bytes_read);

    // Reset the read position so that the file's read pointer is not advanced
    // hexi::file_buffer exposes the current read offset, so we can move it back.
    // (file_buffer maintains its own logical read offset separate from FILE* position)
    if (bytes_read > 0) {
        file.rewind_read(bytes_read); // move logical read pointer back by bytes_read
    }

    return header;
}
```

Notes:

- `hexi::binary_stream` is used to perform the read, as shown in the repo examples.
- The function reads up to `header_size` bytes, then rewinds the `file_buffer`’s logical read position so the caller can later read the file from the beginning as if nothing had happened.
- The exact method name for rewinding (`rewind_read`) may differ slightly depending on the final `file_buffer` API in your repo; if the actual API uses something like `advance_read` with a signed offset, replace the rewind call with the appropriate equivalent, for example:
  ```cpp
  file.advance_read(-static_cast<long>(bytes_read));
  ```

