#include <hexi/file_buffer.h>
#include <hexi.h>              // for hexi::binary_stream
#include <cstdint>
#include <filesystem>
#include <stdexcept>

int32_t read_int32_from_file(const std::filesystem::path& file_path) {
    // open file in binary read mode using Hexi's file_buffer
    hexi::file_buffer fb(file_path.string().c_str(), "rb");
    if (!fb.is_open()) {
        throw std::runtime_error("Failed to open file for reading int32_t");
    }

    // wrap the file_buffer with a binary_stream
    hexi::binary_stream stream(fb);

    int32_t value{};
    stream >> value;

    if (!stream) {
        throw std::runtime_error("Failed to read int32_t from file");
    }

    return value;
}

float read_float_from_file(const std::filesystem::path& file_path) {
    // open file in binary read mode using Hexi's file_buffer
