    std::vector<uint8_t> data2 = {40, 50, 60};

    write_data_to_buffer(buffer, data1);
    write_data_to_buffer(buffer, data2);

    auto result1 = read_data_from_buffer(buffer, data1.size());
    auto result2 = read_data_from_buffer(buffer, data2.size());

    EXPECT_EQ(data1, result1);
    EXPECT_EQ(data2, result2);
}

