template<std::size_t buffer_size = 1024>
void write_data_to_buffer(
    hexi::static_buffer<std::byte, buffer_size>& buffer,
    const std::vector<std::uint8_t>& data
) {
    // Convert input data to std::byte and write into the buffer.
    // Assumes static_buffer has a write(const void*, std::size_t) member
    // with behavior similar to dynamic_buffer in the tests.
    if (data.empty()) {
        return;
    }

    buffer.write(
        static_cast<const void*>(data.data()),
        data.size()
    );
}

template<std::size_t buffer_size = 1024>
std::vector<std::uint8_t> read_data_from_buffer(
    hexi::static_buffer<std::byte, buffer_size>& buffer,
    std::size_t bytes_to_read
) {
    // Read bytes_to_read bytes from the buffer into a std::vector<uint8_t>.
    // Assumes static_buffer has a read(void*, std::size_t) member.
    std::vector<std::uint8_t> result;
    if (bytes_to_read == 0) {
        return result;
    }

    result.resize(bytes_to_read);
    buffer.read(
        static_cast<void*>(result.data()),
        bytes_to_read
    );

    return result;
}
