TEST(StaticBuffer, CapacitySizeFreeRelationship) {
    hexi::static_buffer<std::byte, 1024> buffer;
    std::vector<uint8_t> data(50, 0xFF);
    buffer.write(data.data(), data.size());

    auto info = get_buffer_info(buffer);

    EXPECT_EQ(info.capacity, info.current_size + info.free_space);
}

