```cpp
#include <hexi/static_buffer.h>

template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;
    size_t current_size;
    size_t free_space;
};

// Helper functions that conceptually match the requested ones:
//
// get_buffer_capacity  -> total capacity of the static_buffer
// get_buffer_size      -> current readable data size
// get_buffer_free_space-> remaining writable space
//
// These rely on the interface of hexi::static_buffer, which provides
// size() for readable data and supports the standard array-like size().
template<std::size_t N>
std::size_t get_buffer_capacity(const hexi::static_buffer<std::byte, N>& buffer) {
    // static_buffer is backed by a std::array<storage_type, N>, so capacity is N.
    // Use decltype to depend on the actual type, then size() to query it.
