```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>
#include <algorithm>

template<size_t buffer_size = 1024>
std::vector<std::uint8_t> preview_buffer_data(
    const hexi::static_buffer<std::byte, buffer_size>& buffer,
    std::size_t bytes_to_preview
) {
    // We assume static_buffer exposes a const buffer_read-like interface,
    // including size(), read_offset(), and operator[] for indexed access
    // without modifying the internal read position.

    const std::size_t available = buffer.size();
    const std::size_t to_copy   = std::min(available, bytes_to_preview);

    std::vector<std::uint8_t> out;
    out.reserve(to_copy);

    // Start preview from the current read offset.
    const std::size_t start = buffer.read_offset();

    for (std::size_t i = 0; i < to_copy; ++i) {
        // Access by index should not advance the internal read pointer.
        std::byte b = buffer[start + i];
        out.push_back(static_cast<std::uint8_t>(b));
    }

    return out;
}
