#include <hexi/static_buffer.h>
#include <cstdint>
#include <cstring>  // for std::memcpy
#include <bit>      // for std::endian (C++20)

namespace detail {

// Convert a uint32_t to 4 bytes in little-endian order
inline void uint32_to_le_bytes(std::uint32_t value, std::byte* out) {
#if defined(__BYTE_ORDER__) && __BYTE_ORDER__ == __ORDER_LITTLE_ENDIAN__
    // Host is little-endian: can copy directly
    std::memcpy(out, &value, sizeof(value));
#else
    // Portable manual little-endian encoding
    out[0] = static_cast<std::byte>(value & 0xFF);
    out[1] = static_cast<std::byte>((value >> 8) & 0xFF);
    out[2] = static_cast<std::byte>((value >> 16) & 0xFF);
    out[3] = static_cast<std::byte>((value >> 24) & 0xFF);
#endif
}

// Convert 4 little-endian bytes to uint32_t
inline std::uint32_t le_bytes_to_uint32(const std::byte* in) {
#if defined(__BYTE_ORDER__) && __BYTE_ORDER__ == __ORDER_LITTLE_ENDIAN__
    std::uint32_t value;
    std::memcpy(&value, in, sizeof(value));
    return value;
#else
    return (static_cast<std::uint32_t>(in[0])      ) |
           (static_cast<std::uint32_t>(in[1]) <<  8) |
           (static_cast<std::uint32_t>(in[2]) << 16) |
           (static_cast<std::uint32_t>(in[3]) << 24);
#endif
}

} // namespace detail

template<std::size_t buffer_size = 1024>
void write_uint32_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                            std::uint32_t value) {
    std::byte bytes[sizeof(std::uint32_t)];
    detail::uint32_to_le_bytes(value, bytes);

    // Use static_buffer's write template: write<T>(const T& value)
    // but here we have raw bytes; we can use the raw write method if available.
    // Most simply: write each byte using the byte-oriented interface.
    for (std::size_t i = 0; i < sizeof(std::uint32_t); ++i) {
        buffer.write(bytes[i]);
    }
}

template<std::size_t buffer_size = 1024>
std::uint32_t read_uint32_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer) {
    std::byte bytes[sizeof(std::uint32_t)];

    for (std::size_t i = 0; i < sizeof(std::uint32_t); ++i) {
        bytes[i] = buffer.read();
    }

    return detail::le_bytes_to_uint32(bytes);
}
