#include <hexi/pmc/stream_base.h>
#include <hexi/shared.h>

size_t get_stream_size(const hexi::pmc::stream_base& stream) {
    // stream_base holds a reference to a buffer_base (buffer_).
    // buffer_base derives from buffer_read, which exposes size().
    //
    // stream_base does not expose the buffer directly, but buffer_read's
    // size() is a virtual function, so we can access it via a reference
    // to buffer_read obtained by dynamic_cast.
    //
    // This relies on the fact that all concrete buffers used with
    // stream_base are also buffer_read implementations, which is
    // consistent with Hexi's design.
    const auto* buf_read = dynamic_cast<const hexi::pmc::buffer_read*>(&stream.get_buffer());
    if (!buf_read) {
        // If for some reason the cast fails, fall back to 0.
        return 0;
    }
    return buf_read->size();
}

bool is_stream_empty(const hexi::pmc::stream_base& stream) {
    return get_stream_size(stream) == 0;
}

struct StreamInfo {
    hexi::stream_state state;
    size_t buffer_size;
    bool is_empty;
};

StreamInfo get_stream_state_info(const hexi::pmc::stream_base& stream) {
    StreamInfo info{};
    info.state = stream.get_state();
    info.buffer_size = get_stream_size(stream);
    info.is_empty = (info.buffer_size == 0);
    return info;
}
