#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& stream) {
        // In Hexi, binary_stream_* support operator<< and operator>>
        // for primitive and std::string types.
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // Use the object's serialise method with the writer
    auto& non_const_data = const_cast<UserData&>(data);
    non_const_data.serialise(writer);
}

void deserialize_object(hexi::pmc::binary_stream_reader& reader, UserData& data) {
    // Reuse the same serialise method for reading;
    // the reader also implements operator>>/<< but
    // Hexi's serialisation pattern uses a single serialise method.
    data.serialise(reader);
}
