#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Write length as a 32-bit unsigned integer (prefix), then the raw bytes
    std::uint32_t size = static_cast<std::uint32_t>(str.size());
    writer.write(size);
    if (size > 0) {
        writer.write(str.data(), size);
    }
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read length prefix, then read that many bytes into the string
    std::uint32_t size = 0;
    reader.read(size);

    std::string result;
    result.resize(size);
    if (size > 0) {
        reader.read(result.data(), size);
    }
    return result;
}
