#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Write the element count first
    std::uint32_t count = static_cast<std::uint32_t>(container.size());
    writer.write(count);

    // Then write each element
    for (std::uint32_t value : container) {
        writer.write(value);
    }
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read the element count
    std::uint32_t count = 0;
    reader.read(count);

    std::vector<std::uint32_t> container;
    container.reserve(count);

    // Read each element
    for (std::uint32_t i = 0; i < count; ++i) {
        std::uint32_t value = 0;
        reader.read(value);
        container.push_back(value);
    }

    return container;
}
