// Include the implementation
#include "implementation.hpp"

TEST(BufferAdaptor, WriteReadData) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t original_value = 12345;
    uint8_t original_data[] = {1, 2, 3, 4, 5};

    write_data_to_buffer(adaptor, original_value, original_data, sizeof(original_data));

    uint32_t read_value = 0;
    uint8_t read_data[5] = {0};

    // Reset read position
    adaptor.clear();

    read_data_from_buffer(adaptor, read_value, read_data, sizeof(read_data));

    EXPECT_EQ(original_value, read_value);
    EXPECT_EQ(0, std::memcmp(original_data, read_data, sizeof(original_data)));
}

TEST(BufferAdaptor, GetBufferInfo) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t value = 42;
    adaptor.write(&value, sizeof(value));

    auto info = get_buffer_info(adaptor);

    EXPECT_EQ(sizeof(value), info.size);
    EXPECT_GT(info.free_space, 0);
}

TEST(BufferAdaptor, WriteReadMultiple) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    uint32_t val1 = 100, val2 = 200;
    adaptor.write(&val1, sizeof(val1));
    adaptor.write(&val2, sizeof(val2));

    adaptor.clear();

    uint32_t r1 = 0, r2 = 0;
    adaptor.read(&r1, sizeof(r1));
    adaptor.read(&r2, sizeof(r2));

    EXPECT_EQ(val1, r1);
    EXPECT_EQ(val2, r2);
}

