#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read.h>
#include <vector>
#include <cstdint>
#include <cstddef>

std::size_t find_byte_in_buffer(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte value
) {
    using hexi::pmc::buffer_read;

    // Iterate over readable bytes using the buffer_read interface
    const std::size_t sz = buffer.size();
    for (std::size_t i = 0; i < sz; ++i) {
        if (buffer[i] == value) {
            return i;
        }
    }

    return buffer_read::npos;
}

std::size_t find_delimiter_position(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte delimiter
) {
    // Reuse the generic byte finder
    return find_byte_in_buffer(buffer, delimiter);
}

bool check_buffer_contains(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte value
) {
    using hexi::pmc::buffer_read;

    // If the position is not npos, the value exists in the buffer
    return find_byte_in_buffer(buffer, value) != buffer_read::npos;
}
