#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/binary_stream.h>
#include <vector>
#include <cstdint>
#include <cstddef>

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::size_t bytes) {
    // Use a binary_stream over the adaptor and rely on its skip functionality.
    hexi::binary_stream stream(buffer);
    stream.skip(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    hexi::binary_stream stream(buffer);

    MessageHeader header{};
    // Read fields in the order they are stored in the buffer.
    stream >> header.message_type;
    stream >> header.body_length;

    // Skip the body based on the length field.
    stream.skip(header.body_length);

    return header;
}
