```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // The buffer_adaptor exposes the underlying contiguous storage via data().
    // The current read position is tracked internally as an offset from data().
    // There is no public API to query that offset, so the best we can do with
    // the public Hexi interface is to return the base pointer to the data.
    //
    // Callers that need logical "read pointer" information should combine this
    // with higher‑level state (e.g., size(), empty(), or their own offset
    // tracking) rather than relying on the internal read index of buffer_adaptor.
    return static_cast<const void*>(buffer.data());
}

struct BufferState {
    std::size_t size;
    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferState state{};
    state.size = buffer.size();
    state.read_ptr = get_read_pointer(buffer);
    state.is_empty = buffer.empty();
    return state;
}
