```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

// Returns true if [src, src + src_len) overlaps with [dst, dst + dst_len)
bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
	// Zero-length regions never overlap
	if (src_len == 0 || dst_len == 0) {
		return false;
	}

	auto src_begin = static_cast<const std::byte*>(src);
	auto dst_begin = static_cast<const std::byte*>(dst);

	auto src_end = src_begin + src_len;
	auto dst_end = dst_begin + dst_len;

	// Standard half-open range overlap test:
	// [a1, a2) and [b1, b2) overlap iff a1 < b2 && b1 < a2
	return (src_begin < dst_end) && (dst_begin < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
	// Treat zero-length copy as trivially safe
	if (length == 0) {
		return true;
	}

	// If regions overlap, do not perform the copy
	if (check_regions_overlap(source, length, destination, length)) {
		return false;
	}

	// Non-overlapping: safe to use memcpy
	std::memcpy(destination, source, length);
	return true;
}
