#include "implementation.hpp"

TEST(ExceptionInfo, ExtractUnderrunInfo) {
    try {
        std::vector<std::byte> buffer(10);
        hexi::pmc::buffer_adaptor adaptor(buffer);

        std::vector<std::byte> dest(100);
        adaptor.read(dest.data(), 100);
    } catch (const hexi::buffer_underrun& e) {
        auto details = extract_underrun_info(e);

        EXPECT_EQ(100, details.read_size);
        EXPECT_LE(details.limit_or_size, 10);
        EXPECT_FALSE(details.message.empty());
    }
}

TEST(ExceptionInfo, ExtractReadLimitInfo) {
    try {
        std::vector<std::byte> buffer(1000);
        hexi::pmc::buffer_adaptor adaptor(buffer);
        hexi::pmc::binary_stream stream(adaptor, 5);

        uint32_t values[10] = {0};
        for (int i = 0; i < 10; ++i) {
            stream >> values[i];
        }
    } catch (const hexi::stream_read_limit& e) {
        auto details = extract_read_limit_info(e);

        EXPECT_EQ(5, details.limit_or_size);
        EXPECT_FALSE(details.message.empty());
    }
}

TEST(ExceptionInfo, GetExceptionMessage) {
    try {
        std::vector<std::byte> buffer(10);
        hexi::pmc::buffer_adaptor adaptor(buffer);

        std::vector<std::byte> dest(100);
        adaptor.read(dest.data(), 100);
    } catch (const hexi::buffer_underrun& e) {
        std::string message = get_exception_message(e);

        EXPECT_FALSE(message.empty());
        EXPECT_NE(std::string::npos, message.find("Buffer underrun"));
    }
}

TEST(ExceptionInfo, ExtractMultipleFields) {
    try {
        std::vector<std::byte> buffer(50);
        hexi::pmc::buffer_adaptor adaptor(buffer);

        // Write some data first
        uint8_t data[30] = {0};
        adaptor.write(data, 30);
        adaptor.clear();

        // Try to read more than available
        std::vector<std::byte> dest(100);
        adaptor.read(dest.data(), 100);
    } catch (const hexi::buffer_underrun& e) {
        auto details = extract_underrun_info(e);

        EXPECT_EQ(100, details.read_size);
        EXPECT_LE(details.limit_or_size, 30);
        EXPECT_GE(details.total_read, 0);
        EXPECT_FALSE(details.message.empty());
    }
}

