// Include the implementation
#include "implementation.hpp"

TEST(CompactPacket, SerializeDeserialize) {
    CompactPacket original;
    original.packet_id = 12345;
    original.tags = {"tag1", "tag2", "tag3"};
    original.data = "test data";

    auto buffer = serialize_compact_packet(original);
    ASSERT_FALSE(buffer.empty());

    CompactPacket deserialized = deserialize_compact_packet(buffer);

    EXPECT_EQ(original.packet_id, deserialized.packet_id);
    EXPECT_EQ(original.tags, deserialized.tags);
    EXPECT_EQ(original.data, deserialized.data);
}

TEST(CompactPacket, CompactEncoding) {
    CompactPacket packet;
    packet.packet_id = 100;
    packet.tags = {"small"};
    packet.data = "tiny";

    auto buffer = serialize_compact_packet(packet);

    // Varint encoding should use fewer bytes for small values
    // Verify the buffer is reasonably compact
    EXPECT_LT(buffer.size(), 50);

    CompactPacket deserialized = deserialize_compact_packet(buffer);
    EXPECT_EQ(packet.packet_id, deserialized.packet_id);
