std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // use a std::vector<uint8_t> as the underlying buffer
    std::vector<uint8_t> buffer;

    // create a buffer adaptor that writes into the vector
    hexi::buffer_adaptor adaptor(buffer);

    // create a binary_stream on top of the adaptor
    hexi::binary_stream stream(adaptor);

    // prefixed_varint adaptor wraps the stream and encodes size prefixes as varints
    auto var_stream = hexi::prefixed_varint(stream);

    // packet_id is a fixed-width integer, write it directly to the base stream
    stream << packet.packet_id;

    // tags and data should use prefixed_varint for their size prefixes
    var_stream << packet.tags;
    var_stream << packet.data;

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet{};

    // create a read-only buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

