    hexi::binary_stream stream(adaptor);

    // wrap with prefixed_varint adaptor for compact size prefixes
    auto var_stream = hexi::prefixed_varint(stream);

    // read packet_id directly
    stream >> packet.packet_id;

    // read tags and data using varint-prefixed sizes
    var_stream >> packet.tags;
    var_stream >> packet.data;

    return packet;
}
