std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    // Use a std::vector<uint8_t> as the underlying buffer
    std::vector<uint8_t> buffer;

    // Create a Hexi buffer adaptor and binary stream over it
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Write header
    stream << packet.header;

    // Write data with length prefix (Hexi does this automatically for std::string)
    stream << packet.data;

    // Write fixed 16-byte padding filled with 0x00
    stream.fill<16>(0x00);

    // Write footer
    stream << packet.footer;

    return buffer;
}
