#include <gtest/gtest.h>
#include <hexi/pmc/buffer_base.h>
#include <vector>
#include <cstddef>

// Include the implementation
#include "implementation.hpp"

TEST(CustomBuffer, EmptyBuffer) {
    CustomBuffer buffer;

    EXPECT_TRUE(buffer.empty());
    EXPECT_EQ(0, buffer.size());
}

TEST(CustomBuffer, SizeAfterAddingData) {
    CustomBuffer buffer;

    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5};
    buffer.add_data(test_data.data(), test_data.size());

    EXPECT_FALSE(buffer.empty());
    EXPECT_EQ(5, buffer.size());
}

TEST(CustomBuffer, EmptyAfterClear) {
    CustomBuffer buffer;

    std::vector<uint8_t> test_data = {10, 20, 30};
    buffer.add_data(test_data.data(), test_data.size());

    EXPECT_FALSE(buffer.empty());
    EXPECT_EQ(3, buffer.size());

    buffer.clear();

    EXPECT_TRUE(buffer.empty());
    EXPECT_EQ(0, buffer.size());
}

TEST(CustomBuffer, MultipleAdditions) {
    CustomBuffer buffer;

    std::vector<uint8_t> data1 = {1, 2};
    std::vector<uint8_t> data2 = {3, 4, 5};

    buffer.add_data(data1.data(), data1.size());
    EXPECT_EQ(2, buffer.size());

    buffer.add_data(data2.data(), data2.size());
    EXPECT_EQ(5, buffer.size());
    EXPECT_FALSE(buffer.empty());
}

TEST(CustomBuffer, LargeBuffer) {
    CustomBuffer buffer;

    std::vector<uint8_t> large_data(1000, 0xFF);
    buffer.add_data(large_data.data(), large_data.size());

    EXPECT_FALSE(buffer.empty());
    EXPECT_EQ(1000, buffer.size());
}

