```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // backing storage for the adaptors
    std::vector<std::uint8_t> buffer;
    buffer.resize(input_data.size());

    // write data into the buffer via buffer_write_adaptor
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // make sure there is enough free space before writing
    if (write_adaptor.free() >= input_data.size()) {
        write_adaptor.write(input_data.data(), input_data.size());
    } else {
        // if not enough space, only write as much as fits
        const std::size_t writable = write_adaptor.free();
        write_adaptor.write(input_data.data(), writable);
        buffer.resize(writable);
    }

    // read data back via buffer_read_adaptor
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // size() is the amount of data available to read
    const std::size_t readable = read_adaptor.size();
    std::vector<std::uint8_t> output(readable);

    if (readable != 0) {
        read_adaptor.read(output.data(), readable);
    }

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data,
                                                 std::size_t peek_size) {
    // use buffer_read_adaptor to read from the provided data
    hexi::pmc::buffer_read_adaptor read_adaptor(const_cast<std::vector<std::uint8_t>&>(buffer_data));

    // limit peek_size to what is actually available
    const std::size_t available = read_adaptor.size();
    const std::size_t actual_peek = std::min(peek_size, available);

    std::vector<std::uint8_t> peeked(actual_peek);

    if (actual_peek == 0) {
        return peeked;
    }

    // read_ptr() gives the current read position
    const std::uint8_t* current_ptr =
        static_cast<const std::uint8_t*>(read_adaptor.read_ptr());

    // copy() allows peeking without advancing the read cursor
    read_adaptor.copy(peeked.data(), actual_peek);

    // current_ptr should still be valid and unchanged for the adaptor
    (void)current_ptr; // suppress unused variable warning

    // now actually consume the data using read()
    std::vector<std::uint8_t> consumed(actual_peek);
    read_adaptor.read(consumed.data(), actual_peek);

    return peeked;
}
