#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

struct TypedData {
    uint32_t id;
    int16_t value;
    double ratio;
};

std::vector<uint8_t> write_typed_data(const TypedData& data) {
    // Create an underlying byte buffer
    std::vector<std::uint8_t> buffer;

    // Create a Hexi PMC buffer write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    // Use the template write(auto& source) to write each field in order
    adaptor.write(data.id);
    adaptor.write(data.value);
    adaptor.write(data.ratio);

    return buffer;
}

TypedData read_typed_data(const std::vector<uint8_t>& buffer) {
    TypedData result{};

    // Create a Hexi PMC buffer read adaptor over the const buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    // Use the template read(T* destination) to read back in the same order
    adaptor.read(&result.id);
    adaptor.read(&result.value);
    adaptor.read(&result.ratio);

    return result;
}
