```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

// Writes the provided chunks into a pmc buffer in multiple calls to write(),
// checking free() before each write. Returns the final size() of the buffer.
std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Choose some capacity for the underlying pmc buffer. In a real use‑case this
    // would be provided/configured from elsewhere. Here we just pick a capacity
    // large enough for typical test input, but still demonstrate use of free().
    constexpr std::size_t kCapacity = 4096;

    hexi::pmc::buffer_write_adaptor adaptor(kCapacity);

    for (const auto& chunk : chunks) {
        std::size_t offset = 0;

        while (offset < chunk.size()) {
            // Check how much space is left before each write
            std::size_t available = adaptor.free();
            if (available == 0) {
                // No more space; stop writing further data
                return adaptor.size();
            }

            // Write as much of the remaining part of this chunk as fits
            std::size_t to_write = std::min<std::size_t>(available, chunk.size() - offset);
            adaptor.write(chunk.data() + offset, to_write);
            offset += to_write;
        }
    }

    // Return the final amount of data stored in the buffer
    return adaptor.size();
}

// Reads from a pmc buffer in partial chunks of at most chunk_size bytes until
// the buffer is empty. Uses size() to track remaining data after each read.
// Returns all data read as a single contiguous vector.
std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    if (chunk_size == 0 || buffer.empty()) {
        return {};
    }

    // Create a read adaptor that reads from the given buffer.
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    std::vector<uint8_t> result;
    result.reserve(buffer.size());

    while (adaptor.size() > 0) {
        // Decide how much to read this iteration
        std::size_t to_read = std::min<std::size_t>(chunk_size, adaptor.size());

        std::vector<uint8_t> temp(to_read);
        adaptor.read(temp.data(), to_read);

        // After read(), adaptor.size() has decreased by to_read; we could check it
        // here again if needed.

        // Append the partial data to the result
        result.insert(result.end(), temp.begin(), temp.end());
    }

    return result;
}
