```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a read adaptor over the const buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    Header header{};

    // Peek at the header bytes without consuming them
    // copy() reads from the current read position but does not advance it
    adaptor.copy(&header, sizeof(Header));

    // Use read_ptr() to verify that the read position has not advanced:
    // after copy(), the read pointer should still point to the beginning.
    const std::byte* ptr = adaptor.read_ptr();
    if (!buffer.empty()) {
        // Ensure the pointer is at the start of the buffer
        // (this is just a safety check; in normal use you might omit this)
        if (ptr != reinterpret_cast<const std::byte*>(buffer.data())) {
            // In a real application, you might handle this differently
            // Here we simply do nothing special; header already holds the peeked data
        }
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    std::vector<uint8_t> result;

    if (buffer.empty()) {
        return result;
    }

    // Peek at the first byte without consuming
    uint8_t first = 0;
    adaptor.copy(&first, sizeof(first));

    // Example condition: only read the rest of the buffer if the first byte is non‑zero
    if (first != 0) {
        // Now actually consume data from the adaptor.
        // read() advances the internal read cursor.

        // First read the initial byte we already peeked
        uint8_t consumed_first = 0;
        adaptor.read(&consumed_first, sizeof(consumed_first));

        // Sanity: consumed_first should equal the peeked value
        (void)consumed_first;

        // Read the remainder of the buffer
        const auto remaining = adaptor.size();
        result.resize(1 + remaining);
        result[0] = first;

        if (remaining > 0) {
            adaptor.read(result.data() + 1, remaining);
        }
    }

    return result;
}
