std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    std::vector<uint8_t> result;

    if (buffer.empty()) {
        return result;
    }

    // Peek at the first byte without consuming
    uint8_t first = 0;
    adaptor.copy(&first, sizeof(first));

    // Example condition: only read the rest of the buffer if the first byte is non‑zero
    if (first != 0) {
        // Now actually consume data from the adaptor.
        // read() advances the internal read cursor.

        // First read the initial byte we already peeked
        uint8_t consumed_first = 0;
        adaptor.read(&consumed_first, sizeof(consumed_first));

        // Sanity: consumed_first should equal the peeked value
        (void)consumed_first;

        // Read the remainder of the buffer
        const auto remaining = adaptor.size();
        result.resize(1 + remaining);
        result[0] = first;

        if (remaining > 0) {
            adaptor.read(result.data() + 1, remaining);
        }
    }

    return result;
}

