    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    // Use a dynamic buffer that can grow as we write into it
    hexi::dynamic_buffer<> buffer;

    // Wrap the buffer with a buffer_adaptor and binary_stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    using hexi::endian::native_to_big;

    // 1. message_id (uint32_t)
    uint32_t be_message_id = native_to_big(packet.message_id);
    stream.write(be_message_id);

    // 2. data_values: first write count (uint32_t in big-endian)
    uint32_t count = static_cast<uint32_t>(packet.data_values.size());
    uint32_t be_count = native_to_big(count);
    stream.write(be_count);

    // Prepare a temporary container of big-endian values
    std::vector<uint16_t> be_values;
    be_values.reserve(packet.data_values.size());
    for (uint16_t v : packet.data_values) {
        be_values.push_back(native_to_big(v));
    }

    // Write the big-endian vector contents
    stream.write_container(be_values);

    // 3. checksum (uint32_t)
    uint32_t be_checksum = native_to_big(packet.checksum);
    stream.write(be_checksum);

    // Copy the internal buffer contents to a std::vector<uint8_t>
    std::vector<uint8_t> out(buffer.size());
    if (!out.empty()) {
        buffer.read(out.data(), out.size(), 0); // read from offset 0
    }
    return out;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    // Create a read-only adaptor over the incoming span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    using hexi::endian::big_to_native;

    ProtocolPacket packet{};

    // 1. message_id (uint32_t)
    uint32_t be_message_id = 0;
    stream.read(be_message_id);
    packet.message_id = big_to_native(be_message_id);

    // 2. data_values count (uint32_t)
    uint32_t be_count = 0;
    stream.read(be_count);
    uint32_t count = big_to_native(be_count);

    // 3. data_values contents (vector<uint16_t> in big-endian)
    std::vector<uint16_t> be_values;
    be_values.resize(count);
    stream.read_container(be_values);

    packet.data_values.resize(count);
    for (uint32_t i = 0; i < count; ++i) {
        packet.data_values[i] = big_to_native(be_values[i]);
    }

    // 4. checksum (uint32_t)
    uint32_t be_checksum = 0;
    stream.read(be_checksum);
    packet.checksum = big_to_native(be_checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    // Read-only adaptor over the span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    using hexi::endian::big_to_native;

    ProtocolHeader header{};

    // Create a zero-copy span view of the first 4 bytes (message_id)
    auto id_span = stream.span<std::uint8_t>(sizeof(std::uint32_t));

    // Interpret the span as a big-endian uint32_t
    uint32_t be_message_id = 0;
    // Assuming contiguous storage; copy to local variable
    std::memcpy(&be_message_id, id_span.data(), sizeof(uint32_t));

    header.message_id = big_to_native(be_message_id);

    // Advance the stream past the header
    stream.skip(sizeof(uint32_t));

    return header;
