#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    // Serialisation (writing) – const adaptor
    void serialise(auto& adaptor) const {
        using hexi::endian::conditional_reverse;

        // 1. Write sensor_id directly (no explicit endian conversion requested)
        adaptor.write(sensor_id);

        // 2. Write number of temperatures so deserialisation knows how many to read
        std::uint32_t count = static_cast<std::uint32_t>(temperatures.size());
        adaptor.write(count);

        // 3. Convert each temperature from native to little-endian and write
        for (float t : temperatures) {
            float le_t = conditional_reverse(std::endian::native, std::endian::little, t);
            adaptor.write(le_t);
        }

        // 4. Convert pressure from native to little-endian and write
        double le_p = conditional_reverse(std::endian::native, std::endian::little, pressure);
        adaptor.write(le_p);
    }

    // Deserialisation (reading) – non-const adaptor
    void serialise(auto& adaptor) {
        using hexi::endian::little_to_native_inplace;

        // 1. Read sensor_id directly
        adaptor.read(sensor_id);

        // 2. Read number of temperatures
        std::uint32_t count = 0;
        adaptor.read(count);
        temperatures.resize(count);

        // 3. Read each temperature (stored as little-endian) and convert in-place to native
        for (std::uint32_t i = 0; i < count; ++i) {
            adaptor.read(temperatures[i]);
            little_to_native_inplace(temperatures[i]);
        }

        // 4. Read pressure (stored as little-endian) and convert in-place to native
        adaptor.read(pressure);
        little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Backing buffer for output
    std::vector<std::uint8_t> buffer;

    // Create a buffer adaptor and binary_stream over it
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use stream's serialise method on the entire structure
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData result;

    // Read-only buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use stream's deserialise method on the entire structure
    stream.deserialise(result);

    return result;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    SensorInfo info{};

    // 1. Try to view a null-terminated sensor name string (if present).
    //    If not present, this should give an empty view or fail according to Hexi's semantics;
    //    we assume it returns an empty view when no name is present.
    info.sensor_name = stream.view<char>();

    // 2. Before reading sensor_id, ensure there is enough data
    stream.enforce_read_bounds(sizeof(std::uint32_t));

    // 3. Read the sensor_id directly
    stream.read(info.sensor_id);

    // 4. Skip remaining data (temperatures, pressure, etc.)
    //    We can skip until the end of the buffer. The adaptor knows current read position and size.
    auto remaining = adaptor.size() - adaptor.read_pos();
    stream.skip(remaining);

    return info;
}
